import{_ as e,o as s,c as n,a2 as i}from"./chunks/framework.BnBoz4Zl.js";const t="/anjian-workbuddy-bluebook-site/assets/001_image_J9BUbk5hHo.f3JGw1H0.png",u=JSON.parse('{"title":"第 12 章 从整理桌面文件这些小事做起","description":"桌面发票是典型的“电脑在替人承受混乱”的场景：电子发票、截图、PDF、微信下载文件、邮件附件混在一起，命名方式各不相同。人不在电脑前时，最烦的不是不知道怎么报销，而是不知道哪几张发票已经在电脑里、哪些字段还缺、哪些文件可能重复。","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 12 章 从整理桌面文件这些小事做起/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 12 章 从整理桌面文件这些小事做起/index.md","lastUpdated":1783659790000}'),l={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 12 章 从整理桌面文件这些小事做起/index.md"};function p(o,a,d,r,c,_){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="第-12-章-从整理桌面文件这些小事做起" tabindex="-1">第 12 章 从整理桌面文件这些小事做起 <a class="header-anchor" href="#第-12-章-从整理桌面文件这些小事做起" aria-label="Permalink to &quot;第 12 章 从整理桌面文件这些小事做起&quot;">​</a></h1><h2 id="整理桌面发票-不再回电脑前翻文件" tabindex="-1">整理桌面发票，不再回电脑前翻文件 <a class="header-anchor" href="#整理桌面发票-不再回电脑前翻文件" aria-label="Permalink to &quot;整理桌面发票，不再回电脑前翻文件&quot;">​</a></h2><p>桌面发票是典型的“电脑在替人承受混乱”的场景：电子发票、截图、PDF、微信下载文件、邮件附件混在一起，命名方式各不相同。人不在电脑前时，最烦的不是不知道怎么报销，而是不知道哪几张发票已经在电脑里、哪些字段还缺、哪些文件可能重复。</p><h3 id="场景痛点" tabindex="-1">场景痛点 <a class="header-anchor" href="#场景痛点" aria-label="Permalink to &quot;场景痛点&quot;">​</a></h3><ul><li>发票散落在桌面、下载目录、微信文件目录，格式可能是 PDF、JPG、PNG。</li><li>文件名经常只叫“发票.pdf”“image.png”“微信图片_2026xxxx.jpg”。</li><li>报销真正需要的是结构化字段：抬头、税号、金额、开票日期、发票号码、销售方。</li><li>远程批量整理最怕误删、覆盖、移动原件，导致后面找不回来。</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请帮我整理电脑里的发票，但不要删除、移动或覆盖原文件。</span></span>
<span class="line"><span>扫描范围只包括桌面、Downloads 和微信文件接收目录，时间范围为最近 30 天。</span></span>
<span class="line"><span>候选条件：文件名包含“发票”“电子发票”“invoice”，或内容识别为发票的 PDF、JPG、PNG。</span></span>
<span class="line"><span>第一步先返回候选清单和数量。</span></span>
<span class="line"><span>第二步识别抬头、税号、金额、开票日期、发票号码、销售方、文件路径。</span></span>
<span class="line"><span>第三步生成 invoice-ledger.xlsx，并列出“重复发票”和“无法识别字段”的人工确认清单。</span></span></code></pre></div><p>执行后仅新增台账文件，桌面原发票不移动、不改名、不删除</p><p><img src="`+t+'" alt="" loading="lazy"></p>',8)])])}const b=e(l,[["render",p]]);export{u as __pageData,b as default};
